fn render_markdown(input: &str) -> String {
    let mut output = String::new();
    for line in input.lines() {
        let rendered = render_line(line);
        output.push_str(&rendered);
        output.push('\n');
    }
    output
}

fn render_line(line: &str) -> String {
    let trimmed = line.trim();

    // Handle headings
    if trimmed.starts_with("### ") {
        let text = &trimmed[4..];
        let rendered = render_inline(text).to_uppercase();
        return format!("{}\n{}", rendered, "-".repeat(rendered.len()));
    }
    if trimmed.starts_with("## ") {
        let text = &trimmed[3..];
        let rendered = render_inline(text).to_uppercase();
        return format!("{}\n{}", rendered, "=".repeat(rendered.len()));
    }
    if trimmed.starts_with("# ") {
        let text = &trimmed[2..];
        let rendered = render_inline(text).to_uppercase();
        return format!("{}\n{}", rendered, "=".repeat(rendered.len()));
    }

    // Handle list items
    if trimmed.starts_with("- ") || trimmed.starts_with("* ") {
        let text = &trimmed[2..];
        return format!("  * {}", render_inline(text));
    }

    render_inline(trimmed)
}

fn render_inline(text: &str) -> String {
    let mut result = String::new();
    let chars: Vec<char> = text.chars().collect();
    let len = chars.len();
    let mut i = 0;

    while i < len {
        // Bold: **text**
        if i + 1 < len && chars[i] == '*' && chars[i + 1] == '*' {
            i += 2;
            let start = i;
            while i + 1 < len && !(chars[i] == '*' && chars[i + 1] == '*') {
                i += 1;
            }
            let bold_text: String = chars[start..i].iter().collect();
            result.push_str(&bold_text.to_uppercase());
            if i + 1 < len {
                i += 2; // skip closing **
            }
            continue;
        }

        // Italic: *text*
        if chars[i] == '*' {
            i += 1;
            let start = i;
            while i < len && chars[i] != '*' {
                i += 1;
            }
            let italic_text: String = chars[start..i].iter().collect();
            result.push('_');
            result.push_str(&italic_text);
            result.push('_');
            if i < len {
                i += 1; // skip closing *
            }
            continue;
        }

        // Inline code: `code`
        if chars[i] == '`' {
            i += 1;
            let start = i;
            while i < len && chars[i] != '`' {
                i += 1;
            }
            let code_text: String = chars[start..i].iter().collect();
            result.push('[');
            result.push_str(&code_text);
            result.push(']');
            if i < len {
                i += 1; // skip closing `
            }
            continue;
        }

        // Links: [text](url)
        if chars[i] == '[' {
            i += 1;
            let start = i;
            while i < len && chars[i] != ']' {
                i += 1;
            }
            let link_text: String = chars[start..i].iter().collect();
            if i < len {
                i += 1; // skip ]
            }
            if i < len && chars[i] == '(' {
                i += 1;
                let url_start = i;
                while i < len && chars[i] != ')' {
                    i += 1;
                }
                let url: String = chars[url_start..i].iter().collect();
                if i < len {
                    i += 1; // skip )
                }
                result.push_str(&format!("{} ({})", link_text, url));
            } else {
                result.push('[');
                result.push_str(&link_text);
                result.push(']');
            }
            continue;
        }

        result.push(chars[i]);
        i += 1;
    }

    result
}

fn main() {
    let markdown = r#"# Hello World

This is **bold** and *italic* text.

Use `println!()` to print.

- First item
- Second item

[Rust Book](https://doc.rust-lang.org/book/)"#;

    println!("{}", render_markdown(markdown));
}
